// CollectCompileInputBlobRefs validates CompileInput and returns detached BlobRefs in canonical wire-property traversal order.
func CollectCompileInputBlobRefs(value CompileInput) ([]protocolcommon.BlobRef, error) {
	if _, err := EncodeCompileInput(value); err != nil {
		return nil, err
	}
	refs := make([]protocolcommon.BlobRef, 0)
	for _, blobItem0 := range value.InstalledPackTree {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem0.Blob.BlobID), Digest: protocolcommon.Digest(blobItem0.Blob.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem0.Blob.Lifetime), MediaType: string(blobItem0.Blob.MediaType), Size: protocolcommon.CanonicalUint64(blobItem0.Blob.Size)})
	}
	for _, blobItem1 := range value.ProjectSourceTree {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem1.Blob.BlobID), Digest: protocolcommon.Digest(blobItem1.Blob.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem1.Blob.Lifetime), MediaType: string(blobItem1.Blob.MediaType), Size: protocolcommon.CanonicalUint64(blobItem1.Blob.Size)})
	}
	for _, blobItem2 := range value.ReferencedAssets {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem2.Blob.BlobID), Digest: protocolcommon.Digest(blobItem2.Blob.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem2.Blob.Lifetime), MediaType: string(blobItem2.Blob.MediaType), Size: protocolcommon.CanonicalUint64(blobItem2.Blob.Size)})
	}
	for _, blobItem3 := range value.ResolvedDependencies.Installs {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem3.Manifest.BlobID), Digest: protocolcommon.Digest(blobItem3.Manifest.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem3.Manifest.Lifetime), MediaType: string(blobItem3.Manifest.MediaType), Size: protocolcommon.CanonicalUint64(blobItem3.Manifest.Size)})
	}
	return refs, nil
}

// CollectCompileResultBlobRefs validates CompileResult and returns detached BlobRefs in canonical wire-property traversal order.
func CollectCompileResultBlobRefs(value CompileResult) ([]protocolcommon.BlobRef, error) {
	if _, err := EncodeCompileResult(value); err != nil {
		return nil, err
	}
	refs := make([]protocolcommon.BlobRef, 0)
	for _, blobItem0 := range value.CompiledRecipes.Exports {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem0.CanonicalJSON.BlobID), Digest: protocolcommon.Digest(blobItem0.CanonicalJSON.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem0.CanonicalJSON.Lifetime), MediaType: string(blobItem0.CanonicalJSON.MediaType), Size: protocolcommon.CanonicalUint64(blobItem0.CanonicalJSON.Size)})
	}
	for _, blobItem1 := range value.CompiledRecipes.Queries {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem1.CanonicalJSON.BlobID), Digest: protocolcommon.Digest(blobItem1.CanonicalJSON.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem1.CanonicalJSON.Lifetime), MediaType: string(blobItem1.CanonicalJSON.MediaType), Size: protocolcommon.CanonicalUint64(blobItem1.CanonicalJSON.Size)})
	}
	for _, blobItem2 := range value.CompiledRecipes.Views {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string(blobItem2.CanonicalJSON.BlobID), Digest: protocolcommon.Digest(blobItem2.CanonicalJSON.Digest), Lifetime: protocolcommon.BlobLifetime(blobItem2.CanonicalJSON.Lifetime), MediaType: string(blobItem2.CanonicalJSON.MediaType), Size: protocolcommon.CanonicalUint64(blobItem2.CanonicalJSON.Size)})
	}
	if value.NormalizedArtifact.Pack != nil {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string((*value.NormalizedArtifact.Pack).ArtifactJSON.BlobID), Digest: protocolcommon.Digest((*value.NormalizedArtifact.Pack).ArtifactJSON.Digest), Lifetime: protocolcommon.BlobLifetime((*value.NormalizedArtifact.Pack).ArtifactJSON.Lifetime), MediaType: string((*value.NormalizedArtifact.Pack).ArtifactJSON.MediaType), Size: protocolcommon.CanonicalUint64((*value.NormalizedArtifact.Pack).ArtifactJSON.Size)})
		refs = append(refs, protocolcommon.BlobRef{BlobID: string((*value.NormalizedArtifact.Pack).CanonicalJSON.BlobID), Digest: protocolcommon.Digest((*value.NormalizedArtifact.Pack).CanonicalJSON.Digest), Lifetime: protocolcommon.BlobLifetime((*value.NormalizedArtifact.Pack).CanonicalJSON.Lifetime), MediaType: string((*value.NormalizedArtifact.Pack).CanonicalJSON.MediaType), Size: protocolcommon.CanonicalUint64((*value.NormalizedArtifact.Pack).CanonicalJSON.Size)})
	}
	if value.NormalizedArtifact.Project != nil {
		refs = append(refs, protocolcommon.BlobRef{BlobID: string((*value.NormalizedArtifact.Project).ArtifactJSON.BlobID), Digest: protocolcommon.Digest((*value.NormalizedArtifact.Project).ArtifactJSON.Digest), Lifetime: protocolcommon.BlobLifetime((*value.NormalizedArtifact.Project).ArtifactJSON.Lifetime), MediaType: string((*value.NormalizedArtifact.Project).ArtifactJSON.MediaType), Size: protocolcommon.CanonicalUint64((*value.NormalizedArtifact.Project).ArtifactJSON.Size)})
		refs = append(refs, protocolcommon.BlobRef{BlobID: string((*value.NormalizedArtifact.Project).CanonicalJSON.BlobID), Digest: protocolcommon.Digest((*value.NormalizedArtifact.Project).CanonicalJSON.Digest), Lifetime: protocolcommon.BlobLifetime((*value.NormalizedArtifact.Project).CanonicalJSON.Lifetime), MediaType: string((*value.NormalizedArtifact.Project).CanonicalJSON.MediaType), Size: protocolcommon.CanonicalUint64((*value.NormalizedArtifact.Project).CanonicalJSON.Size)})
	}
	return refs, nil
}
